# Abstract base classes implementing interfaces from types_module
from types_module import IShape, Color, Point

@abstract
class ShapeBase(IShape):
    _color: Color
    _position: Point

    def __init__(self, color: Color, position: Point):
        self._color = color
        self._position = position

    def describe_position(self) -> str:
        return f"Shape at ({self._position.x}, {self._position.y})"

    @virtual
    def get_type_name(self) -> str:
        return "BaseShape"

    # Virtual property for color - subclasses must override to expose
    @virtual
    def get_color(self) -> Color:
        return self._color

    @virtual
    def get_position(self) -> Point:
        return self._position

