# Concrete shape implementations with cross-module inheritance
from base_classes import ShapeBase
from types_module import Point, Color

class Rectangle(ShapeBase):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color, position: Point):
        super().__init__(color, position)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def get_type_name(self) -> str:
        return "Rectangle"

    @override
    def get_color(self) -> Color:
        return self._color

    @override
    def get_position(self) -> Point:
        return self._position

class Circle(ShapeBase):
    radius: float

    def __init__(self, radius: float, color: Color, position: Point):
        super().__init__(color, position)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def get_type_name(self) -> str:
        return "Circle"

    @override
    def get_color(self) -> Color:
        return self._color

    @override
    def get_position(self) -> Point:
        return self._position
